Here's how to implement all three requirements:

## 1. Custom "Cancel" Back Button (in `EditProductPage.xaml`)

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.EditProductPage">

    <Shell.BackButtonBehavior>
        <BackButtonBehavior TextOverride="Cancel"
                           Command="{Binding CancelCommand}" />
    </Shell.BackButtonBehavior>

    <!-- page content -->
</ContentPage>
```

## 2. Guard Navigation in `AppShell.xaml.cs`

Use `OnNavigating` with `GetDeferral()` to intercept back navigation and show a confirmation dialog:

```csharp
public partial class AppShell : Shell
{
    public AppShell()
    {
        InitializeComponent();
    }

    protected override async void OnNavigating(ShellNavigatingEventArgs args)
    {
        base.OnNavigating(args);

        // Only intercept back navigation from EditProductPage
        if (args.Source == ShellNavigationSource.Pop &&
            CurrentPage is EditProductPage editPage &&
            editPage.BindingContext is EditProductViewModel vm &&
            vm.HasUnsavedChanges)
        {
            var deferral = args.GetDeferral();

            bool discard = await CurrentPage.DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard them?",
                "Discard", "Stay");

            if (!discard)
                args.Cancel();   // user chose "Stay"

            deferral.Complete(); // always call this
        }
    }
}
```

## 3. ViewModel with Cancel Command

```csharp
public partial class EditProductViewModel : ObservableObject
{
    [ObservableProperty]
    private bool hasUnsavedChanges;

    [RelayCommand]
    private async Task Cancel()
    {
        // This triggers OnNavigating above
        await Shell.Current.GoToAsync("..");
    }
}
```

**Key points:**
- `GetDeferral()` is required for async operations (like `DisplayAlert`) inside `OnNavigating` — without it you'll hit race conditions.
- Always call `deferral.Complete()` whether you cancel or not.
- The `BackButtonBehavior.Command` handles the custom button tap; the `OnNavigating` guard catches swipe-back and hardware back button too.
